const raw = $json.body ?? $json;

const DEFAULT_SQL = "SELECT r.id, r.quality_id, r.name, r.type, r.`desc`, r.src_db, r.src_tbl, r.dest_db, r.dest_tbl, r.src_value, r.dest_value, r.diff, r.`begin`, r.`end`, r.result, r.status, r.src_error, r.dest_error, r.is_repaired, r.created_at, r.updated_at, s.src_sql AS src_sql, s.dest_sql AS dest_sql, s.msg_template AS msg_template FROM wattrel_quality_result r LEFT JOIN wattrel_quality_setting s ON r.quality_id = s.id WHERE r.result = 1 AND r.created_at >= DATE_SUB(NOW(), INTERVAL 3 DAY) ORDER BY r.created_at DESC LIMIT ?";

const COUNTRIES = {
  CN: {
    key: 'cn', name: '中国', host: '10.20.47.14', port: 36000,
    envFiles: ['/root/CN-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  PH: {
    key: 'ph', name: '菲律宾', host: '10.20.10.12', port: null,
    envFiles: ['/root/PH-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  INE: {
    key: 'ine', name: '印尼', host: '192.168.21.236', port: 36000,
    envFiles: ['/root/INE-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  MX: {
    key: 'mx', name: '墨西哥', host: '172.20.220.165', port: 36000,
    envFiles: ['/root/MX-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  TH: {
    key: 'th', name: '泰国', host: '192.168.20.236', port: 36000,
    envFiles: ['/root/TH-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
  PK: {
    key: 'pk', name: '巴基斯坦', host: '10.20.84.176', port: null,
    envFiles: ['/root/PK-Intelligent-Alarm-Repair-Assistant/.env.local', '/root/Global-Intelligent-Alarm-Repair-Assistant/.env.local'],
  },
};

function shellQuote(value) {
  return `'${String(value).replace(/'/g, `'\\''`)}'`;
}

function sqlLiteral(value) {
  if (value === null || value === undefined) return 'NULL';
  if (typeof value === 'number' && Number.isFinite(value)) return String(value);
  return `'${String(value).replace(/\\/g, '\\\\').replace(/'/g, "''")}'`;
}

function interpolateSql(sql, params) {
  let index = 0;
  return String(sql || '').replace(/\?/g, () => sqlLiteral(params[index++]));
}

function normalizeParams(params, limit) {
  if (!Array.isArray(params) || params.length === 0) return [limit];
  return params.map((item) => (item === '${limit}' || item === '{limit}' ? limit : item));
}

function normalizeCountry(value) {
  const code = String(value || '').trim().toUpperCase();
  if (code === 'ID' || code === 'INDONESIA') return 'INE';
  if (code === 'PHILIPPINES') return 'PH';
  return code;
}

function buildLoadEnvBlock(envFiles) {
  const envFileList = envFiles.map(shellQuote).join(' ');
  return [
    `for env_file in ${envFileList}; do`,
    '  if [ -f "$env_file" ]; then',
    '    set -a',
    '    . "$env_file"',
    '    set +a',
    '    break',
    '  fi',
    'done',
  ].join('\n');
}

function buildMysqlScript(country, sqlB64) {
  return [
    'set -euo pipefail',
    buildLoadEnvBlock(country.envFiles),
    ': "${DB_HOST:?DB_HOST missing from wattrel env file}"',
    ': "${DB_PORT:?DB_PORT missing from wattrel env file}"',
    ': "${DB_USER:?DB_USER missing from wattrel env file}"',
    ': "${DB_PASSWORD:?DB_PASSWORD missing from wattrel env file}"',
    ': "${DB_NAME:?DB_NAME missing from wattrel env file}"',
    `printf %s ${shellQuote(sqlB64)} | base64 -d | MYSQL_PWD="$DB_PASSWORD" mysql --batch --raw --silent --host="$DB_HOST" --port="$DB_PORT" --user="$DB_USER" "$DB_NAME"`,
  ].join('\n');
}

function buildCountryCommand(code, country, sqlB64, requestId) {
  const meta = JSON.stringify({ countryCode: code, countryKey: country.key, countryName: country.name, requestId });
  const mysqlScript = buildMysqlScript(country, sqlB64);
  const remoteScript = [
    'set -euo pipefail',
    `printf '%s\\n' ${shellQuote(`__WATTREL_META__${meta}`)}`,
    buildLoadEnvBlock(country.envFiles),
    'DB_EXEC_HOST="${WATTREL_DB_EXEC_HOST:-${WATTREL_DS_SSH_HOST:-${DS_SSH_HOST:-${DS_HOST:-}}}}"',
    'DB_EXEC_USER="${WATTREL_DB_EXEC_USER:-${WATTREL_DS_SSH_USER:-root}}"',
    'DB_EXEC_PORT="${WATTREL_DB_EXEC_PORT:-${WATTREL_DS_SSH_PORT:-}}"',
    'if [ -n "$DB_EXEC_HOST" ]; then',
    '  ssh_args="-o BatchMode=yes -o ConnectTimeout=20"',
    '  if [ -n "$DB_EXEC_PORT" ]; then ssh_args="$ssh_args -p $DB_EXEC_PORT"; fi',
    `  ssh $ssh_args "$DB_EXEC_USER@$DB_EXEC_HOST" ${shellQuote(`bash -lc ${shellQuote(mysqlScript)}`)}`,
    'else',
    `  bash -lc ${shellQuote(mysqlScript)}`,
    'fi',
  ].join('\n');

  const sshParts = ['ssh'];
  if (country.port) sshParts.push('-p', String(country.port));
  sshParts.push('-o BatchMode=yes', '-o ConnectTimeout=20', shellQuote(`root@${country.host}`), shellQuote(`bash -lc ${shellQuote(remoteScript)}`));
  return sshParts.join(' ');
}

const countryCode = normalizeCountry(raw.countryCode || raw.country);
const country = COUNTRIES[countryCode];
const limit = Math.max(1, Math.min(1000, Number(raw.limit || 1000) || 1000));
const params = normalizeParams(raw.params, limit);
const sql = interpolateSql(raw.sql || DEFAULT_SQL, params).replace(/;*\s*$/, '') + ';';
const requestId = String(raw.request_id || raw.requestId || `wattrel-${Date.now()}`);
const errors = [];

if (!country) errors.push(`unsupported country: ${countryCode || '(empty)'}`);
if (!sql.trim()) errors.push('sql is required');

if (errors.length) {
  return [{ json: { valid: false, errors, country: '', countryCode, countryName: raw.countryName || '', requestId } }];
}

const sqlB64 = Buffer.from(sql, 'utf8').toString('base64');
const commands = Object.fromEntries(Object.entries(COUNTRIES).map(([code, item]) => [code, buildCountryCommand(code, item, sqlB64, requestId)]));

return [{
  json: {
    valid: true,
    country: country.key,
    countryCode,
    countryName: raw.countryName || country.name,
    requestId,
    limit,
    commands,
  },
}];

const raw = $json;
const stdout = String(raw.stdout || raw.data || '');
const stderr = String(raw.stderr || raw.error?.message || '').trim();
const exitCode = raw.code ?? raw.exitCode ?? (raw.error ? 1 : 0);

function parseValue(value) {
  if (value === undefined || value === 'NULL') return null;
  if (/^-?\d+(?:\.\d+)?$/.test(value)) {
    const n = Number(value);
    if (Number.isFinite(n)) return n;
  }
  return value;
}

const lines = stdout.split(/\r?\n/).filter((line) => line.length > 0);
let meta = {};
if (lines[0]?.startsWith('__WATTREL_META__')) {
  try { meta = JSON.parse(lines.shift().replace('__WATTREL_META__', '')); } catch {}
}

if (Number(exitCode) !== 0) {
  return [{ json: { success: false, country: meta.countryKey || '', countryCode: meta.countryCode || '', countryName: meta.countryName || '', requestId: meta.requestId || '', rows: [], rowCount: 0, error: { code: 'COMMAND_FAILED', message: stderr || 'ssh/mysql command failed', exit_code: exitCode } } }];
}

if (!lines.length) {
  return [{ json: { success: true, country: meta.countryKey || '', countryCode: meta.countryCode || '', countryName: meta.countryName || '', requestId: meta.requestId || '', rows: [], rowCount: 0 } }];
}

const headers = lines[0].split('\t');
const rows = lines.slice(1).map((line) => {
  const values = line.split('\t');
  return Object.fromEntries(headers.map((header, index) => [header, parseValue(values[index])]));
});

return [{ json: { success: true, country: meta.countryKey || '', countryCode: meta.countryCode || '', countryName: meta.countryName || '', requestId: meta.requestId || '', rows, rowCount: rows.length } }];
